19	function emptyDraftRow(): RoomColorSchemeRow {
20	  return {
21	    programmeCode: '',
22	    department: '',
23	    schemeColorHex: '#888888',
24	  };
25	}
26	
27	function initialDraftRows(schemeRowsFromDoc: RoomColorSchemeRow[]): RoomColorSchemeRow[] {
28	  return schemeRowsFromDoc.length ? schemeRowsFromDoc.map((r) => ({ ...r })) : [emptyDraftRow()];
29	}
