86	          >
87	            <label className="flex min-w-0 flex-col text-[10px] text-muted">
88	              programme
89	              <input
90	                className="mt-0.5 truncate rounded border border-border bg-background px-1 py-0.5 font-mono text-[10px]"
91	                value={row.programmeCode ?? ''}
92	                onChange={(e) => {
93	                  const v = e.target.value;
94	                  setDraftRows((rows) =>
95	                    rows.map((x, i) => (i === idx ? { ...x, programmeCode: v } : x)),
96	                  );
97	                }}
98	              />
99	            </label>
100	            <label className="flex min-w-0 flex-col text-[10px] text-muted">
101	              department
102	              <input
103	                className="mt-0.5 truncate rounded border border-border bg-background px-1 py-0.5 font-mono text-[10px]"
104	                value={row.department ?? ''}
105	                onChange={(e) => {
106	                  const v = e.target.value;
107	                  setDraftRows((rows) =>
108	                    rows.map((x, i) => (i === idx ? { ...x, department: v } : x)),
109	                  );
